 17	  ChartVoronoiContainer,
 18	  ChartGroup,
 19	  ChartArea,
 20	  ChartStack,
 21	  ChartLine,
 22	  ChartThemeColor,
 23	  Chart,
 24	  ChartAxis,
 25	} from '@patternfly/react-charts/victory';
 26	
 27	export const AreaChart: React.FC<AreaChartProps> = ({
 28	  data = [],
 29	  formatDate = timeFormatter.format,
 30	  humanize = humanizeNumber,
 31	  loading = true,
 32	  query,
 33	  ariaChartLinkLabel,
 34	  ariaChartTitle,
 35	  xAxis = true,
 36	  yAxis = true,
 37	  chartStyle,
 38	  byteDataType = '',
 39	  mainDataName,
 40	  chartType,
 41	  tickCount = 4,
 42	  height = 200,
 43	  showLegend,
 44	  legendComponent,
 45	}) => {
 46	  const [containerRef, width] = useRefWidth();
 47	
 48	  const { processedData, unit } = React.useMemo(() => {
 49	    const nonEmptyDataSets = data.filter((dataSet) => dataSet?.length);
 50	    if (byteDataType) {
 51	      return processFrame(nonEmptyDataSets, byteDataType);
 52	    }
 53	    return { processedData: nonEmptyDataSets, unit: '' };
 54	  }, [byteDataType, data]);
 55	
 56	  const xTickFormat = React.useCallback(
 57	    (tick) => formatDate(tick),
 58	    [formatDate]
 59	  );
 60	  const yTickFormat = React.useCallback(
 61	    (tick) => `${humanize(tick, unit, unit).string}`,
 62	    [humanize, unit]
 63	  );
 64	
 65	  const getLabel = React.useCallback(
 66	    (prop: { datum: DataPoint<Date> }, includeDate = true) => {
 67	      const { x, y } = prop.datum;
 68	      const value = humanize(y, unit, unit).string;
 69	      const date = formatDate(x);
 70	      return includeDate
 71	        ? i18n.t('{{value}} at {{date}}', { value, date })
 72	        : value;
 73	    },
 74	    [humanize, unit, formatDate]
 75	  );
 76	
 77	  const legendData = processedData.map((d) => ({
 78	    childName: d[0].description,
 79	    name: d[0].description,
 80	    symbol: d[0].symbol,
 81	  }));
 82	
 83	  const container = React.useMemo(() => {
 84	    if (processedData?.length > 1 || showLegend) {
 85	      return (
 86	        <CursorVoronoiContainer
 87	          activateData={false}
 88	          cursorDimension="x"
 89	          labels={(props) => getLabel(props, false)}
 90	          mouseFollowTooltips
 91	          labelComponent={
 92	            <ChartLegendTooltip
 93	              stack
 94	              legendData={legendData}
 95	              getLabel={getLabel}
 96	              formatDate={(d) => formatDate(d[0].x)}
 97	              mainDataName={mainDataName}
 98	            />
 99	          }
100	          voronoiDimension="x"
101	        />
102	      );
103	    }
104	    return (
105	      <ChartVoronoiContainer
106	        voronoiDimension="x"
107	        labels={getLabel}
108	        activateData={false}
109	      />
110	    );
111	  }, [
112	    formatDate,
113	    getLabel,
114	    legendData,
115	    showLegend,
116	    mainDataName,
117	    processedData,
118	  ]);
119	
120	  let CustomChartGroup = ChartGroup;
121	  let CustomChartArea = ChartArea;
122	
123	  if (chartType === 'stacked-area') {
124	    CustomChartGroup = ChartStack;
125	  }
126	
127	  if (chartType === 'grouped-line') {
128	    CustomChartArea = ChartLine;
129	    CustomChartGroup = ChartGroup;
130	  }
131	
132	  return (
133	    <PrometheusGraph ref={containerRef}>
134	      <PrometheusGraphLink
135	        query={query}
136	        ariaChartLinkLabel={ariaChartLinkLabel}
137	      >
138	        {processedData?.length ? (
139	          <Chart
140	            ariaTitle={ariaChartTitle}
141	            containerComponent={container}
142	            domainPadding={{ y: 20 }}
143	            height={height}
144	            width={width}
145	            themeColor={ChartThemeColor.multiUnordered}
146	            scale={{ x: 'time', y: 'linear' }}
147	            padding={{ top: 20, left: 70, bottom: 60, right: 0 }}
148	            legendData={chartType && showLegend ? legendData : null}
149	            legendPosition="bottom-left"
150	            legendComponent={legendComponent}
151	          >
152	            {xAxis && (
153	              <ChartAxis tickCount={tickCount} tickFormat={xTickFormat} />
154	            )}
155	            {yAxis && (
156	              <ChartAxis
157	                dependentAxis
158	                tickCount={tickCount}
159	                tickFormat={yTickFormat}
160	              />
161	            )}
162	            <CustomChartGroup height={height} width={width}>
163	              {processedData.map((datum, index) => (
164	                <CustomChartArea
165	                  // eslint-disable-next-line react/no-array-index-key
166	                  key={index}
167	                  data={datum}
168	                  style={chartStyle && chartStyle[index]}
169	                  name={datum[0]?.description}
170	                />
171	              ))}
172	            </CustomChartGroup>
173	          </Chart>
174	        ) : (
175	          <GraphEmpty height={height} loading={loading} />
176	        )}
177	      </PrometheusGraphLink>
178	    </PrometheusGraph>
179	  );
180	};
181	
182	export type AreaChartProps = {
183	  formatDate?: (date: Date, showSeconds?: boolean) => string;
184	  humanize?: Humanize;
185	  loading?: boolean;
186	  query?: string | string[];
187	  ariaChartLinkLabel?: string;
188	  ariaChartTitle?: string;
189	  data?: DataPoint[][];
190	  xAxis?: boolean;
191	  yAxis?: boolean;
192	  chartStyle?: object[];
193	  byteDataType?: ByteDataTypes; // Use this to process the whole data frame at once
194	  mainDataName?: string;
195	  chartType?: 'stacked-area' | 'grouped-line';
196	  tickCount?: number;
197	  height?: number;
198	  showLegend?: boolean;
199	  legendComponent?: React.ReactElement<any>;
200	};

