182	export type AreaChartProps = {
183	  formatDate?: (date: Date, showSeconds?: boolean) => string;
184	  humanize?: Humanize;
185	  loading?: boolean;
186	  query?: string | string[];
187	  ariaChartLinkLabel?: string;
188	  ariaChartTitle?: string;
189	  data?: DataPoint[][];
190	  xAxis?: boolean;
191	  yAxis?: boolean;
192	  chartStyle?: object[];
193	  byteDataType?: ByteDataTypes; // Use this to process the whole data frame at once
194	  mainDataName?: string;
195	  chartType?: 'stacked-area' | 'grouped-line';
196	  tickCount?: number;
197	  height?: number;
198	  showLegend?: boolean;
199	  legendComponent?: React.ReactElement<any>;
200	};
